package com.seaquake6324.civitas.application;
import com.seaquake6324.civitas.application.port.PopulationRepository;import com.seaquake6324.civitas.domain.population.*;import java.util.UUID;
/** Revision-checked permanent-death state change; source authorization remains an infrastructure concern. */
public final class KillCitizenService{public Result killFromInvasion(PopulationRepository repository,UUID id,long expectedRevision,long now){return kill(repository,id,expectedRevision,now,CitizenDeathCause.INVASION);}public Result kill(PopulationRepository repository,UUID id,long expectedRevision,long now,CitizenDeathCause cause){if(cause==null||cause==CitizenDeathCause.NONE)return new Result(false,Failure.INVALID_CAUSE,null);CitizenRecord current=repository.citizen(id).orElse(null);if(current==null)return new Result(false,Failure.MISSING,null);if(current.revision()!=expectedRevision)return new Result(false,Failure.STALE,current);if(!current.alive())return new Result(false,Failure.ALREADY_DEAD,current);CitizenRecord dead=current.die(now,cause);repository.putCitizen(dead);return new Result(true,null,dead);}public enum Failure{MISSING,STALE,ALREADY_DEAD,INVALID_CAUSE}public record Result(boolean success,Failure failure,CitizenRecord citizen){}}
